:root {
  --bg-board: #0a0a1a;
  --bg-header: #12122a;
  --border-main: #ff00ff;
  --border-inner: #00ffff;
  --color-title: #ffff00;
  --color-subtitle: #00ffff;
  --color-gold: #ffd700;
  --color-silver: #c0c8d8;
  --color-bronze: #cd7f32;
  --color-normal: #e0e0ff;
  --color-badge-bg: #1a1a3a;
  --color-dots: #333366;
  --color-footer: #ff00ff;
  --color-icon: #ff00ff;
  --row-hover: #1a1a3a;
}

.arcade-board {
  width: 420px;
  background-color: var(--bg-board);
  border: 3px solid var(--border-main);
  border-radius: 8px;
  padding: 0;
  margin: 0 auto;
  overflow: hidden;
}

.board-header {
  background-color: var(--bg-header);
  border-bottom: 2px solid var(--border-inner);
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 12px;
  padding: 14px 20px 10px;
}

.header-icon {
  font-size: 18px;
  color: var(--color-icon);
}

.board-title {
  font-size: 26px;
  font-weight: 900;
  letter-spacing: 6px;
  color: var(--color-title);
  margin: 0;
  line-height: 1;
}

.board-subtitle {
  text-align: center;
  font-size: 11px;
  font-weight: 700;
  letter-spacing: 4px;
  color: var(--color-subtitle);
  padding: 8px 0 12px;
  border-bottom: 1px solid var(--border-inner);
}

.score-list {
  padding: 8px 16px;
  display: flex;
  flex-direction: column;
  gap: 4px;
}

.score-row {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 8px 10px;
  border-radius: 4px;
  border: 1px solid var(--color-dots);
}

.rank-badge {
  font-size: 11px;
  font-weight: 800;
  letter-spacing: 1px;
  background-color: var(--color-badge-bg);
  padding: 3px 6px;
  border-radius: 3px;
  min-width: 32px;
  text-align: center;
}

.rank-gold .rank-badge { color: var(--color-gold); }
.rank-silver .rank-badge { color: var(--color-silver); }
.rank-bronze .rank-badge { color: var(--color-bronze); }
.rank-normal .rank-badge { color: var(--color-normal); }

.player-name {
  font-size: 16px;
  font-weight: 900;
  letter-spacing: 3px;
  min-width: 40px;
}

.rank-gold .player-name { color: var(--color-gold); }
.rank-silver .player-name { color: var(--color-silver); }
.rank-bronze .player-name { color: var(--color-bronze); }
.rank-normal .player-name { color: var(--color-normal); }

.score-dots {
  flex: 1;
  height: 2px;
  border-top: 2px dotted var(--color-dots);
}

.score-value {
  font-size: 15px;
  font-weight: 800;
  letter-spacing: 1px;
}

.rank-gold .score-value { color: var(--color-gold); }
.rank-silver .score-value { color: var(--color-silver); }
.rank-bronze .score-value { color: var(--color-bronze); }
.rank-normal .score-value { color: var(--color-normal); }

.board-footer {
  border-top: 2px solid var(--border-inner);
  padding: 10px;
  text-align: center;
}

.footer-text {
  font-size: 12px;
  font-weight: 700;
  letter-spacing: 4px;
  color: var(--color-footer);
}
